const baseArticles = [
  {
    url: "basearticle",
    title: 'Tytuł Głównego Artykułu',
    description: "W podanym opisie znajdą się najważniejsze informacje dotyczące artykułu.",
    image: '',
    date: "1 I 1970 RW",
    imageText: 'Opis zdjęcia do głównego artykułu',
    imageLabel: 'Opis zdjęcia do głównego artykułu',
    linkText: 'Kontynuuj czytanie...',
  },
  {
    url: "proceedingarticle",
    title: 'Tytuł Następnego Artykułu',
    description: "W podanym opisie znajdą się najważniejsze informacje dotyczące artykułu.",
    image: '',
    date: "1 I 1970 RW",
    imageText: 'Opis zdjęcia do głównego artykułu',
    imageLabel: 'Opis zdjęcia do głównego artykułu',
    linkText: 'Kontynuuj czytanie...',
  }
]

export default function Articles() {
  const [articles, setArticles] = useState(baseArticles)
  const [display, setDisplay] = useState(baseArticles)

  useEffect(() => {
    const getArticles = async () => {
      const serverData = await fetchArticles()
      setArticles(serverData)
      setDisplay(serverData)
    }
    getArticles()
  }, [])

  const fetchArticles = async () => {
    const res = await fetch(Data.fetchArticleList)
    const json = await res.json()
    return json
  }

  const searchArticle = (e: any) => {
    const query = e.target.value;
    const temp = [];
    for (let index = 0; index < articles.length; index++) {
      if ((articles[index].title.toLowerCase().includes(query.toLowerCase()) || query.toLowerCase().includes((articles[index].description)))) {
        temp.push(articles[index]);
      }
    }
    setDisplay(temp);
  }

  return (
    <>
      <Container maxWidth="lg">
        <Header title="Rafist0" sections={Data.sections} />
        <main>
          <MainFeaturedPost post={articles[0]} />
          <Grid container spacing={4}>
            {articles.slice(1, 3).map((post) => (
              <FeaturedPost key={post.title} post={post} />
            ))}
          </Grid>
          <Grid container spacing={5} sx={{ mt: 3 }}>
            <Grid item xs={12} md={8}>
              <Typography>Wszystkie artykuły</Typography>
              <ol>
                {display.map((post) => (
                  <li style={{ paddingBottom: "10px" }} key={post.title}>
                    <Link sx={{ color: "#fff", fontSize: "15pt" }} className="" href={"#/articles/" + post.url}>{post.title}</Link>
                    <br />
                    <Typography sx={{ fontStyle: "italic", fontSize: "12pt" }}>{post.description}</Typography>
                  </li>
                ))}
                {/* {[...Array(articles.length - display.length)].map((x, i) =>
                  <li style={{ paddingBottom: "10px" , display:"none"}} key={i}>
                    <Link sx={{ color: "#fff", fontSize: "15pt"}} className="" href={"#/articles/"}>Title</Link>
                    <br />
                    <Typography sx={{ fontStyle: "italic", fontSize: "12pt" }}>Description</Typography>
                  </li>
                )} */}
              </ol>
            </Grid>
            <Grid item xs={12} md={4}>
              <TextField
                id="__poemsearch"
                label="Wyszukaj artykuł"
                type="search"
                variant="filled"
                fullWidth
                InputProps={{
                  inputProps: {
                    style: { textAlign: "center" },
                  }
                }}
                style={{ display: "inline-block" }}
                onChange={(e) => { searchArticle(e) }}>
              </TextField>
            </Grid>
            <div style={{display:"none"}}>
            <Sidebar
              title={sidebar.title}
              description={sidebar.description}
              archives={sidebar.archives}
              social={sidebar.social}
            />
            </div>
          </Grid>
        </main>
      </Container>
      <Footer
        title="Artykuły RW"
        description="Szczerze i od serca 💖"
      />
    </>
  );
}
