import { Grid, Link, Typography } from '@mui/material'
import React from 'react'

interface PoemSidebarProps {
    poems: ReadonlyArray<{
        title: string;
        description: string;
        url: string;
    }>;
    currentPoem: string;
}

const PoemSidebar = (props: PoemSidebarProps) => {
    const { poems, currentPoem } = props;
    return (
        <Grid item xs={12} md={4}>
            <Typography sx={{ color: "#fff", fontSize: "15pt" }}>Pozostałe wiersze:</Typography>
            <ul>
                {
                    poems.map((poem) => {
                        if (poem.title !== currentPoem) {
                            return (
                                <li key={poem.title}>
                                    <Link sx={{ color: "#fff", fontSize: "15pt" }} className="" href={"#/poems/" + poem.url}>{poem.title}</Link>
                                    <br />
                                    <Typography sx={{ fontStyle: "italic", fontSize: "12pt" }}>{poem.description}</Typography>
                                </li>
                            )
                        }
                        return (
                            <li key={poem.title}>
                                <Link sx={{ color: "gray", fontSize: "15pt" }} className="" href={"#/poems/" + poem.url}>{poem.title}</Link>
                                <br />
                                <Typography sx={{ color: "gray", fontStyle: "italic", fontSize: "12pt" }}>{poem.description}</Typography>
                            </li>
                        )
                    }
                    )
                }
            </ul>
        </Grid>
    )
}

export default PoemSidebar