import React from 'react'
import { Link } from 'react-router-dom';
import '../../static/css/PoemListing.css';
import HistoryEduIcon from '@mui/icons-material/HistoryEdu';
import { Box, Button, Typography } from '@mui/material';

interface PoemTilesProps {
    display: ReadonlyArray<{
        url: string;
        id: string;
        date: string;
        title: string;
        description: string;
    }>;
}

const PoemTiles = (props: PoemTilesProps) => {
    const {display} = props;
    return (
        <>
        {
        display.map((poem) =>
            <div key={poem.id} className="__poemrecord" id={poem.title}>
                <div className="poemlisting" key={poem.id ? poem.id : "ID does not exist"}>
                    <Box sx={{ backgroundColor: "grey.900", padding: "5px", marginBlock: "10px", borderRadius: "7px", boxShadow: "1px 1px 0px 1px grey" }}>
                        <div style={{ display: 'inline-flex', verticalAlign: "middle", alignItems: 'center', flexWrap: 'wrap' }}>
                            <HistoryEduIcon color="primary" />
                            <Typography color="primary" variant="h6">&nbsp;{poem.title ? poem.title : "Tytuł niedostępny"}</Typography>
                        </div>
                        <Typography className="recordid">{poem.id ? poem.id : "Tytuł niedostępny"}</Typography>
                        <p className="recorddate" style={{ marginBlockEnd: "8px" }} >{poem.date ? poem.date : "Data niedostępna"}</p>
                        <p className="recorddescription" style={{ marginInline: "20px" }}>{poem.description ? poem.description : "Opis niedostępny"}</p>
                        <Link to={poem.url ? "/poems/" + poem.url : "none"}>
                            <Button style={{ margin: "5px" }} variant="outlined">{poem.title}</Button>
                        </Link>
                    </Box>
                </div>
            </div>
        )
        }
        </>
    )
}

export default PoemTiles