import { Container } from '@mui/material'
import React from 'react'
import Footer from '../components/blog/Footer'
import Header from '../components/blog/Header'
import Data from '../utils/Data'

type Props = {}

const Home = (props: Props) => {
  return (
    <Container maxWidth="lg">
    <Header title="Rafist0" sections={Data.sections} />
    <img style={{width:"inherit",height:"500px",objectFit:"cover",borderRadius:"15pt"}} src={Data.homeBannerImage} alt="Falling rainbow star from the top right side"></img>
    <Footer title="Rafał Włodarczyk 2022" description="Szczerze i od serca 💖"/>
    </Container>
  )
}

export default Home